/** Serializable voucher header + lines — dirty-check + Copy. */

export interface VoucherLineSnapshot {
  accountCode: string;
  /** Display-only — hydrate on load; excluded from dirty baseline */
  accountName?: string;
  debitAmount: number;
  description: string;
  costCenterCode?: string;
  customerId?: string;
  customerCode?: string;
  customerName?: string;
  invoiceCode?: string;
  invoiceDate?: string;
  invoiceTotalAmount?: number;
  invoicePaidAmount?: number;
  invoiceRemainingAmount?: number;
}

export interface VoucherFormSnapshot {
  voucherDate: string;
  receiptKind: string;
  customerId: string;
  customerCode: string;
  customerName: string;
  representativeName: string;
  customerPhone: string;
  reference: string;
  /** Display-only — excluded from dirty baseline */
  referenceCustomerName: string;
  accountCode: string;
  /** Display-only — excluded from dirty baseline */
  accountName: string;
  counterAccountCode?: string;
  /** Display-only — excluded from dirty baseline */
  counterAccountName?: string;
  description: string;
  processingLevel: string;
  lines: VoucherLineSnapshot[];
}

/** @deprecated Use VoucherFormSnapshot */
export type CashVoucherFormSnapshot = VoucherFormSnapshot;

export function serializeVoucherSnapshot(s: VoucherFormSnapshot): string {
  return JSON.stringify(s);
}

/** Alias — CashVoucherForm legacy name */
export const serializeCashVoucherSnapshot = serializeVoucherSnapshot;

/** Fields persisted / user-edited — excludes display-only hydrate (accountName, referenceCustomerName). */
function dirtyPayload(s: VoucherFormSnapshot): string {
  return JSON.stringify({
    voucherDate: s.voucherDate,
    receiptKind: s.receiptKind,
    customerId: s.customerId,
    customerCode: s.customerCode,
    representativeName: s.representativeName,
    customerPhone: s.customerPhone,
    reference: s.reference,
    accountCode: s.accountCode,
    counterAccountCode: s.counterAccountCode ?? '',
    description: s.description,
    processingLevel: s.processingLevel,
    lines: s.lines.map(l => ({
      accountCode: l.accountCode,
      debitAmount: Number(l.debitAmount) || 0,
      description: l.description,
      costCenterCode: l.costCenterCode ?? '',
      customerId: l.customerId ?? '',
      invoiceCode: l.invoiceCode ?? '',
    })),
  });
}

export function snapshotsEqual(saved: string | null, currentSerialized: string): boolean {
  if (!saved) return false;
  try {
    const a = JSON.parse(saved) as VoucherFormSnapshot;
    const b = JSON.parse(currentSerialized) as VoucherFormSnapshot;
    return dirtyPayload(a) === dirtyPayload(b);
  } catch {
    return saved === currentSerialized;
  }
}
