import React, { useEffect, useMemo, useState } from 'react';
import {
  Slideout,
  Select,
  Input,
  DateRangeFilter,
  addToast,
  CatalogTableSkeleton,
} from '@linm-soft/common-components';
import type { DateRangeValue, SelectOption } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import type { CashVoucherDto } from '../../services/kt/models';
import type { DatePageFilter } from '../../services/kt/models';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import { ListSearchRefreshButtons } from '../list/ListSearchRefreshButtons';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import erp from '../../styles/erpPage.module.css';

const PAGE_SIZE = DEFAULT_PAGE_SIZE;

export interface VoucherSearchSlideoutProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  testIdPrefix: string;
  /** Session scope — vd. `kt-phieu-thu-search` */
  listScope: string;
  fetchList: (filter?: DatePageFilter) => Promise<{ items: CashVoucherDto[]; totalCount: number }>;
  onOpenVoucher: (id: string, resultIds: string[], items: CashVoucherDto[]) => void;
  /** Filter + cột Mức xử lý — thay Trạng thái (`voucher-list-erp.md` §2.1) */
  processingLevelFilterOptions: SelectOption[];
  formatProcessingLevel: (level: string | undefined) => string;
}

/**
 * Tìm kiếm chứng từ — slide-out giống list page; click dòng mở chứng từ và giữ danh sách để next/prev.
 */
export const VoucherSearchSlideout: React.FC<VoucherSearchSlideoutProps> = ({
  isOpen,
  onClose,
  title,
  testIdPrefix,
  listScope,
  fetchList,
  onOpenVoucher,
  processingLevelFilterOptions,
  formatProcessingLevel,
}) => {
  const dispatch = useAppDispatch();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    processingLevel,
    setProcessingLevel,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(listScope);
  const [items, setItems] = useState<CashVoucherDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(PAGE_SIZE);
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const levelFilterOptions = useMemo(
    () => [{ value: '', label: 'Tất cả mức xử lý' }, ...processingLevelFilterOptions],
    [processingLevelFilterOptions],
  );

  useEffect(() => {
    if (!isOpen || !initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      fetchList({
        fromDate,
        toDate,
        search: search || undefined,
        processingLevel: processingLevel || undefined,
        page,
        pageSize,
      })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatch(addToast({
              message: err instanceof Error ? err.message : 'Lỗi tải danh sách',
              type: 'error',
            }));
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [isOpen, initialized, fromDate, toDate, search, processingLevel, page, pageSize, reloadKey, fetchList, dispatch]);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      setReloadKey(k => k + 1);
    });
  };
  const refresh = () => pulseSearch(() => setReloadKey(k => k + 1));

  const setPageSize = (size: number) => {
    setPageSizeState(size as ListPageSize);
    setPage(1);
  };

  const openRow = (row: CashVoucherDto) => {
    const ids = items.map(i => i.id);
    onOpenVoucher(row.id, ids, items);
    onClose();
  };

  return (
    <Slideout
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      width="720px"
      position="right"
      data-testid={`${testIdPrefix}-search-slideout`}
    >
      <div className={erp.filtersBar} data-testid={`${testIdPrefix}-search-filters`}>
        <div className={erp.field} data-testid={`${testIdPrefix}-field-search`}>
          <Input
            placeholder="Tìm số phiếu, đối tác, diễn giải..."
            value={searchDraft}
            onChange={e => setSearchDraft(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
          />
        </div>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          preset={datePreset}
          onChange={(v: DateRangeValue) => {
            applyDateRange(v.fromDate, v.toDate, v.preset);
            resetPage();
          }}
        />
        <div data-testid={`${testIdPrefix}-filter-processingLevel`}>
          <Select
            value={processingLevel}
            onChange={e => { setProcessingLevel(e.target.value); resetPage(); }}
            options={levelFilterOptions}
          />
        </div>
        <ListSearchRefreshButtons
          testIdPrefix={testIdPrefix}
          onSearch={handleSearch}
          onRefresh={refresh}
        />
      </div>

      <div className={erp.tableCard} style={{ marginTop: 12 }}>
        {showTableLoading ? (
          <CatalogTableSkeleton
            rows={Math.min(pageSize, 8)}
            data-testid={`${testIdPrefix}-table-skeleton`}
          />
        ) : items.length === 0 ? (
          <div className={erp.empty}>Không có dữ liệu</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th>Số phiếu</th>
                  <th>Ngày</th>
                  <th>Đối tác</th>
                  <th>Diễn giải</th>
                  <th className={erp.colAmount}>Số tiền</th>
                  <th>Mức xử lý</th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr
                    key={r.id}
                    className={erp.clickableRow}
                    onClick={() => openRow(r)}
                    data-testid={`${testIdPrefix}-search-row-${r.id}`}
                    style={{ cursor: 'pointer' }}
                  >
                    <td><code>{r.code}</code></td>
                    <td>{formatDateLocal(r.voucherDate)}</td>
                    <td>{r.customerName ?? '—'}</td>
                    <td>{r.description}</td>
                    <td className={erp.amountCell}>{formatVnd(r.amount)}</td>
                    <td data-testid={`${testIdPrefix}-search-row-${r.id}-processing-level`}>
                      {formatProcessingLevel(r.processingLevel)}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {!showTableLoading && (
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        )}
      </div>
      <p style={{ marginTop: 12, fontSize: 12, color: 'var(--color-text-secondary, #6c757d)' }}>
        Nhấn một dòng để mở chứng từ. Dùng nút điều hướng trên thanh công cụ để chuyển giữa các chứng từ trong trang kết quả hiện tại.
      </p>
    </Slideout>
  );
};
